use std::cell::Cell;

struct SafeCounter {
    value: Cell<i32>,
}

impl SafeCounter {
    fn new(initial_value: i32) -> Self {
        SafeCounter { 
            value: Cell::new(initial_value),
        }
    }

    // Method to increment the counter from any location
    fn increment(&self) -> i32 {
        let current = self.value.get();
        let new_value = current + 1;
        self.value.set(new_value);
        new_value
    }

    // Method to reset the counter
    fn reset(&self) -> i32 {
        let initial = 0;
        self.value.set(initial);
        initial
    }

    // Method that reads the current value without changing it
    fn get_current(&self) -> i32 {
        self.value.get()
    }
}

fn main() {
    let counter = SafeCounter::new(10);
    println!("Initial count: {}", counter.get_current());

    // Multiple 'locations' (functions/scopes) can safely modify the same data through '&self'
    let _ = counter.increment(); 
    let _ = counter.increment(); 

    println!("Count after two increments: {}", counter.get_current());

    // Resetting the value from another scope/operation
    let _ = counter.reset(); 
    println!("Count after reset: {}", counter.get_current());
}

use std::cell::Cell;
use std::rc::Rc;

struct Counter {
    value: Cell<i32>,
}

impl Counter {
    fn new(initial_value: i32) -> Self {
        Counter { value: Cell::new(initial_value) }
    }

    // Reads the internal value. This is safe because we only read.
    fn read(&self) -> i32 {
        self.value.get()
    }

    // Mutates the internal value when we have a shared reference to it.
    fn increment(&self) -> i32 {
        let current = self.read();
        self.value.set(current + 1);
        self.read()
    }
}

fn main() {
    // We use Rc because we are simulating multiple owners/references to the counter.
    // Cell<i32> is used here because i32 implements Copy, making it suitable for Cell.
    let shared_counter = Rc::new(Counter::new(10));

    println!("Initial count: {}", shared_counter.read());

    // --- Part 1 Logic ---
    // Simulate one part of the program modifying the value using a direct reference.
    let result1 = shared_counter.increment();
    println!("\n[Part 1] After first increment (Result 1): {}", result1);

    // --- Part 2 Logic ---
    // Simulate another, independent part of the program reading and then modifying it.
    { 
        // In a real scenario, this closure represents isolated logic that needs access.
        let counter_ref = &shared_counter;
        println!("[Part 2] Inside scope - Current value: {}", counter_ref.read());

        // Part 2 performs its own increment
        let result2 = counter_ref.increment();
        println!("[Part 2] After second increment (Result 2): {}", result2);
    }

    // --- Final Check ---
    println!("\nFinal check - Total count: {}", shared_counter.read());
}

use std::cell::Cell;

struct Counter {
    // Cell is used here because the T (i32) implements Copy, 
    // and we need interior mutability through shared references (&Counter).
    value: Cell<i32>,
}

impl Counter {
    fn new(initial_value: i32) -> Self {
        Counter { 
            value: Cell::new(initial_value),
        }
    }

    // This method takes an immutable reference, which is what we want for sharing.
    fn increment(&self) -> i32 {
        // Using .set() provides controlled interior mutability. 
        let new_val = self.value.get() + 1;
        self.value.set(new_val);
        new_val
    }

    fn get_value(&self) -> i32 {
        // Reading the value is straightforward.
        self.value.get()
    }
}

fn main() {
    // Create one instance of the counter that everyone can share.
    let shared_counter = Counter::new(10);

    println!("Initial count: {}", shared_counter.get_value());

    // Because we only have immutable references to 'shared_counter' 
    // (in a real app, this might be wrapped in Arc<Mutex<...>> or similar),
    // the Cell allows us to mutate the internal state safely.
    let count1 = shared_counter.increment();
    println!("After first increment: {}", count1);

    let count2 = shared_counter.increment();
    println!("After second increment: {}", count2);

    // Check the final value through a read-only method.
    println!("Final stored count: {}", shared_counter.get_value());
}

use std::cell::Cell;

struct SharedCounter {
    count: Cell<i32>,
}

impl SharedCounter {
    fn new(initial_value: i32) -> Self {
        SharedCounter { 
            count: Cell::new(initial_value),
        }
    }

    // This function simulates a read-only operation that needs to know the current value.
    fn get(&self) -> i32 {
        self.count.get()
    }

    // This function demonstrates safe, interior mutation using Cell::set().
    fn increment(&self) {
        let current_value = self.count.get();
        println!("\n[Mutation] Current value read: {}", current_value);
        self.count.set(current_value + 1);
        println!("[Mutation] New value set successfully.");
    }
}

fn main() {
    // We initialize the counter once.
    let counter = SharedCounter::new(10);

    println!("--- Initial State ---");
    println!("The initial count is: {}", counter.get());

    // The first operation mutates the state internally.
    counter.increment();

    // Because Cell allows mutation through an immutable reference (&self), 
    // we can call increment again without changing ownership or needing complex locks.
    counter.increment();

    println!("\n--- Final Check ---");
    // We can read the final state, proving the internal change persisted.
    println!("The final count is: {}", counter.get());
}

